h-full min-h-0 min-w-0" style="width: 100%; transform: none;"><div class=""><div class="relative"><div class="" style="transform: none;"><div class="relative z-0 flex max-w-full"><div id="code-block-viewer" dir="ltr" class="q9tKkq_viewer cm-editor z-10 light:cm-light dark:cm-light flex h-full w-full flex-col items-stretch ͼd ͼr"><div class="cm-scroller"><pre class="cm-content q9tKkq_readonly m-0"><code><span class="ͼe">-- ==========================================================</span><span>
</span><span class="ͼe">-- Blood Bank Management System</span><span>
</span><span class="ͼe">-- Database Schema</span><span>
</span><span class="ͼe">-- Author : Ruchitha M</span><span>
</span><span class="ͼe">-- ==========================================================</span><span>

</span><span class="ͼe">-- Create Database</span><span>
</span><span class="ͼg">CREATE</span><span> DATABASE BloodBankDB;

USE BloodBankDB;

</span><span class="ͼe">-- ==========================================================</span><span>
</span><span class="ͼe">-- DONOR TABLE</span><span>
</span><span class="ͼe">-- ==========================================================</span><span>

</span><span class="ͼg">CREATE</span><span> </span><span class="ͼg">TABLE</span><span> Donor (
    DonorID </span><span class="ͼm">INT</span><span> AUTO_INCREMENT </span><span class="ͼg">PRIMARY</span><span> </span><span class="ͼg">KEY</span><span>,
    FullName </span><span class="ͼm">VARCHAR</span><span>(</span><span class="ͼj">100</span><span>) </span><span class="ͼg">NOT</span><span> </span><span class="ͼj">NULL</span><span>,
    Gender ENUM(</span><span class="ͼk">'Male'</span><span>,</span><span class="ͼk">'Female'</span><span>,</span><span class="ͼk">'Other'</span><span>) </span><span class="ͼg">NOT</span><span> </span><span class="ͼj">NULL</span><span>,
    Age </span><span class="ͼm">INT</span><span> </span><span class="ͼg">CHECK</span><span> (Age </span><span class="ͼg">&gt;=</span><span class="ͼj">18</span><span>),
    BloodGroup </span><span class="ͼm">VARCHAR</span><span>(</span><span class="ͼj">5</span><span>) </span><span class="ͼg">NOT</span><span> </span><span class="ͼj">NULL</span><span>,
    Phone </span><span class="ͼm">VARCHAR</span><span>(</span><span class="ͼj">15</span><span>) </span><span class="ͼg">UNIQUE</span><span>,
    Email </span><span class="ͼm">VARCHAR</span><span>(</span><span class="ͼj">100</span><span>),
    Address </span><span class="ͼm">VARCHAR</span><span>(</span><span class="ͼj">255</span><span>),
    LastDonationDate </span><span class="ͼm">DATE</span><span>
);

</span><span class="ͼe">-- ==========================================================</span><span>
</span><span class="ͼe">-- PATIENT TABLE</span><span>
</span><span class="ͼe">-- ==========================================================</span><span>

</span><span class="ͼg">CREATE</span><span> </span><span class="ͼg">TABLE</span><span> Patient (
    PatientID </span><span class="ͼm">INT</span><span> AUTO_INCREMENT </span><span class="ͼg">PRIMARY</span><span> </span><span class="ͼg">KEY</span><span>,
    FullName </span><span class="ͼm">VARCHAR</span><span>(</span><span class="ͼj">100</span><span>) </span><span class="ͼg">NOT</span><span> </span><span class="ͼj">NULL</span><span>,
    Gender ENUM(</span><span class="ͼk">'Male'</span><span>,</span><span class="ͼk">'Female'</span><span>,</span><span class="ͼk">'Other'</span><span>),
    Age </span><span class="ͼm">INT</span><span>,
    BloodGroup </span><span class="ͼm">VARCHAR</span><span>(</span><span class="ͼj">5</span><span>) </span><span class="ͼg">NOT</span><span> </span><span class="ͼj">NULL</span><span>,
    HospitalName </span><span class="ͼm">VARCHAR</span><span>(</span><span class="ͼj">100</span><span>),
    Phone </span><span class="ͼm">VARCHAR</span><span>(</span><span class="ͼj">15</span><span>),
    Address </span><span class="ͼm">VARCHAR</span><span>(</span><span class="ͼj">255</span><span>)
);

</span><span class="ͼe">-- ==========================================================</span><span>
</span><span class="ͼe">-- BLOOD STOCK TABLE</span><span>
</span><span class="ͼe">-- ==========================================================</span><span>

</span><span class="ͼg">CREATE</span><span> </span><span class="ͼg">TABLE</span><span> BloodStock (
    BloodGroup </span><span class="ͼm">VARCHAR</span><span>(</span><span class="ͼj">5</span><span>) </span><span class="ͼg">PRIMARY</span><span> </span><span class="ͼg">KEY</span><span>,
    UnitsAvailable </span><span class="ͼm">INT</span><span> </span><span class="ͼg">NOT</span><span> </span><span class="ͼj">NULL</span><span> </span><span class="ͼg">DEFAULT</span><span> </span><span class="ͼj">0</span><span>
);

</span><span class="ͼe">-- ==========================================================</span><span>
</span><span class="ͼe">-- DONATION TABLE</span><span>
</span><span class="ͼe">-- ==========================================================</span><span>

</span><span class="ͼg">CREATE</span><span> </span><span class="ͼg">TABLE</span><span> Donation (
    DonationID </span><span class="ͼm">INT</span><span> AUTO_INCREMENT </span><span class="ͼg">PRIMARY</span><span> </span><span class="ͼg">KEY</span><span>,
    DonorID </span><span class="ͼm">INT</span><span> </span><span class="ͼg">NOT</span><span> </span><span class="ͼj">NULL</span><span>,
    BloodGroup </span><span class="ͼm">VARCHAR</span><span>(</span><span class="ͼj">5</span><span>),
    UnitsDonated </span><span class="ͼm">INT</span><span> </span><span class="ͼg">DEFAULT</span><span> </span><span class="ͼj">1</span><span>,
    DonationDate </span><span class="ͼm">DATE</span><span>,

    </span><span class="ͼg">FOREIGN</span><span> </span><span class="ͼg">KEY</span><span> (DonorID)
    </span><span class="ͼg">REFERENCES</span><span> Donor(DonorID)
    </span><span class="ͼg">ON</span><span> </span><span class="ͼg">DELETE</span><span> </span><span class="ͼg">CASCADE</span><span>
    </span><span class="ͼg">ON</span><span> </span><span class="ͼg">UPDATE</span><span> </span><span class="ͼg">CASCADE</span><span>,

    </span><span class="ͼg">FOREIGN</span><span> </span><span class="ͼg">KEY</span><span> (BloodGroup)
    </span><span class="ͼg">REFERENCES</span><span> BloodStock(BloodGroup)
    </span><span class="ͼg">ON</span><span> </span><span class="ͼg">DELETE</span><span> </span><span class="ͼg">CASCADE</span><span>
    </span><span class="ͼg">ON</span><span> </span><span class="ͼg">UPDATE</span><span> </span><span class="ͼg">CASCADE</span><span>
);

</span><span class="ͼe">-- ==========================================================</span><span>
</span><span class="ͼe">-- BLOOD REQUEST TABLE</span><span>
</span><span class="ͼe">-- ==========================================================</span><span>

</span><span class="ͼg">CREATE</span><span> </span><span class="ͼg">TABLE</span><span> BloodRequest (
    RequestID </span><span class="ͼm">INT</span><span> AUTO_INCREMENT </span><span class="ͼg">PRIMARY</span><span> </span><span class="ͼg">KEY</span><span>,
    PatientID </span><span class="ͼm">INT</span><span> </span><span class="ͼg">NOT</span><span> </span><span class="ͼj">NULL</span><span>,
    BloodGroup </span><span class="ͼm">VARCHAR</span><span>(</span><span class="ͼj">5</span><span>),
    UnitsRequired </span><span class="ͼm">INT</span><span>,
    RequestDate </span><span class="ͼm">DATE</span><span>,

    Status ENUM(</span><span class="ͼk">'Pending'</span><span>,</span><span class="ͼk">'Approved'</span><span>,</span><span class="ͼk">'Rejected'</span><span>)
    </span><span class="ͼg">DEFAULT</span><span> </span><span class="ͼk">'Pending'</span><span>,

    </span><span class="ͼg">FOREIGN</span><span> </span><span class="ͼg">KEY</span><span> (PatientID)
    </span><span class="ͼg">REFERENCES</span><span> Patient(PatientID)
    </span><span class="ͼg">ON</span><span> </span><span class="ͼg">DELETE</span><span> </span><span class="ͼg">CASCADE</span><span>
    </span><span class="ͼg">ON</span><span> </span><span class="ͼg">UPDATE</span><span> </span><span class="ͼg">CASCADE</span><span>,

    </span><span class="ͼg">FOREIGN</span><span> </span><span class="ͼg">KEY</span><span> (BloodGroup)
    </span><span class="ͼg">REFERENCES</span><span> BloodStock(BloodGroup)
    </span><span class="ͼg">ON</span><span> </span><span class="ͼg">DELETE</span><span> </span><span class="ͼg">CASCADE</span><span>
    </span><span class="ͼg">ON</span><span> </span><span class="ͼg">UPDATE</span><span> </span><span class="ͼg">CASCADE</span><span>
);

</span><span class="ͼe">-- ==========================================================</span><span>
</span><span class="ͼe">-- END OF DATABASE SCHEMA</span><span>
</span><span class="ͼe">-- ==========================================================</span></code></pre></div></div></div></div></div></div></div></div><div class=""><div class="" style="width: 100%; transform: none;"></div></div></div></div></div></div></div></div></pre>
