,\"campaign_key\":\"idea_to_visual_identity\"},\"798449148159\":{\"language_key\":\"hi_latn\",\"campaign_key\":\"cricket_catchup\"},\"1866355576294609\":{\"campaign_key\":\"job_caricature\",\"language_key\":\"ko\"},\"1866358635421714\":{\"language_key\":\"ja\",\"campaign_key\":\"interview_practice\"},\"1868259082036225\":{\"language_key\":\"pt\",\"campaign_key\":\"football_bobblehead\"},\"120246696337550182\":{\"campaign_key\":\"hair_color_preview\",\"language_key\":\"es\"},\"812357871011\":{\"campaign_key\":\"football_bobblehead\",\"language_key\":\"pt\"},\"1868705151718561\":{\"campaign_key\":\"national_team_match_analysis\",\"language_key\":\"es\"},\"120245237712380182\":{\"campaign_key\":\"mini_me_world\",\"language_key\":\"hi_latn\"},\"798449063754\":{\"campaign_key\":\"cricket_catchup\",\"language_key\":\"hi\"},\"1867100481376465\":{\"campaign_key\":\"nearby_trip_planning\",\"language_key\":\"ja\"},\"1867097546221586\":{\"campaign_key\":\"photo_cartoon\",\"language_key\":\"es\"},\"778169782541\":{\"language_key\":\"en\",\"campaign_key\":\"spicy_pani_puri\"},\"801737430134\":{\"campaign_key\":\"bracelet_design\",\"language_key\":\"id\"},\"1868991376259250\":{\"language_key\":\"es\",\"campaign_key\":\"football_bobblehead\"},\"778150297187\":{\"campaign_key\":\"spicy_pani_puri\",\"language_key\":\"hi\"},\"808801747587\":{\"campaign_key\":\"custom_event_sticker\",\"language_key\":\"hi\"},\"120242559330440182\":{\"language_key\":\"en\",\"campaign_key\":\"job_caricature\"},\"812358495329\":{\"campaign_key\":\"football_bobblehead\",\"language_key\":\"hi\"},\"120245715524780182\":{\"campaign_key\":\"personal_color_analysis\",\"language_key\":\"hi\"},\"807141203998\":{\"campaign_key\":\"image_canvas\",\"language_key\":\"ja\"},\"799747618960\":{\"campaign_key\":\"vanity_refresh\",\"language_key\":\"id\"},\"778169782520\":{\"language_key\":\"en\",\"campaign_key\":\"spicy_pani_puri\"},\"120241043845840182\":{\"language_key\":\"en\",\"campaign_key\":\"outfit_transfer\"},\"798559023047\":{\"campaign_key\":\"cricket_catchup\",\"language_key\":\"en\"},\"812175322962\":{\"language_key\":\"ko\",\"campaign_key\":\"football_bobblehead\"},\"808801638153\":{\"campaign_key\":\"custom_event_sticker\",\"language_key\":\"hi\"},\"120245610681080182\":{\"campaign_key\":\"photo_comic_story\",\"language_key\":\"id\"},\"1868259085865169\":{\"campaign_key\":\"football_bobblehead\",\"language_key\":\"pt\"},\"778150297163\":{\"campaign_key\":\"spicy_pani_puri\",\"language_key\":\"en\"},\"120245715524770182\":{\"campaign_key\":\"hairstyle_analysis\",\"language_key\":\"hi_latn\"},\"807332099467\":{\"language_key\":\"id\",\"campaign_key\":\"data_visualization\"},\"120245715524760182\":{\"campaign_key\":\"hairstyle_analysis\",\"language_key\":\"hi_latn\"},\"793910549039\":{\"campaign_key\":\"restaurant_language_practice\",\"language_key\":\"ja\"},\"798449063742\":{\"language_key\":\"hi\",\"campaign_key\":\"cricket_catchup\"},\"778150297166\":{\"language_key\":\"en\",\"campaign_key\":\"spicy_pani_puri\"},\"808807097886\":{\"language_key\":\"hi_latn\",\"campaign_key\":\"custom_event_sticker\"}},\"campaigns\":{\"hairstyle_analysis\":{\"enabled\":true,\"bootstrap_context\":\"You are starting a conversation with a user who arrived from a paid Meta or Instagram campaign. Treat this as a soft signal of possible interest, never as a fact about the user's identity, appearance, gender, hair, photos, language preference, or plans to change their hairstyle.\\n\\nCampaign key: hairstyle_analysis\\nCreative theme: using a portrait to compare several hairstyle directions in a clean, high-resolution visual guide.\\nDemonstrated request: create a portrait-and-panel hairstyle graphic with four or five options and practical tips.\\nUseful workflow for later turns: gather a clear portrait and desired level of change, preserve identity, propose suitable style directions without presenting appearance judgments as facts, visualize the options, and explain tradeoffs.\\n\\nFor the first visible response:\\n- Make hairstyle exploration feel fun and low-commitment, with concrete value around comparing options, visualizing a change, and getting practical styling guidance.\\n- Do not assume the user has uploaded a photo, wants a haircut, or has any particular face shape, hair texture, or style.\\n- Let the continuation choices offer a hairstyle comparison, a subtle refresh, and a bolder visual preview.\\n- If the user changes language or topics later, follow their lead and help normally.\"},\"hair_color_preview\":{\"enabled\":true,\"bootstrap_context\":\"You are starting a conversation with a user who arrived from a paid Meta campaign presented in Spanish. Treat this as a soft signal of possible interest, never as a fact about the user's identity, appearance, nationality, sports interests, photos, language preference, or plans to change their hair.\\n\\nCampaign key: hair_color_preview\\nCreative theme: previewing a playful hair-color idea on a personal photo before deciding whether the look feels right.\\nDemonstrated request: visualize a bold team-inspired color treatment on the person's hair.\\nUseful workflow for later turns: gather one clear photo and a color direction, preserve identity and lighting, create a realistic or intentionally stylized preview, compare alternatives, and describe the result as a visualization rather than a guaranteed salon outcome.\\n\\nFor the first visible response:\\n- Make experimentation feel fun and low-stakes, with concrete value around trying a bold palette, comparing variations, and keeping the person recognizable.\\n- Do not assume the user follows a team, wants the featured colors, has uploaded a photo, or intends to make a real-world change.\\n- Let the continuation choices offer one color preview, a subtler variation, and a side-by-side comparison.\\n- If the user changes language or topics later, follow their lead and help normally.\"},\"custom_event_sticker\":{\"bootstrap_context\":\"You are starting a conversation with a user who arrived from a paid YouTube campaign. Treat this as a soft signal of possible interest, never as a fact about the user's identity, appearance, occupation, creative work, upcoming events, photos, merchandise plans, language, or location.\\n\\nCampaign key: custom_event_sticker\\nCreative theme: turning personal performance photos into a recognizable, exaggerated cutout sticker with playful signature details, then previewing it in color, black-and-white, and on real-world surfaces.\\nDemonstrated request: make memorable stickers from a few personal photos for an upcoming show.\\nUseful context for later turns: the experience can help choose a clean cutout, cartoon, or bold event-merch style; preserve recognizable cues from a supplied photo; create a sticker-ready concept; and explore alternate colors, shapes, text, or mockups.\\n\\nFor the first visible response:\\n- Make the transformation feel personal and delightfully tangible, with concrete value around style direction, recognizable details, and ready-to-share mockups.\\n- Do not assume the user is a musician, has a show, owns the pictured items, resembles the featured subject, or wants merchandise.\\n- Let the continuation choices offer a photo-to-sticker transformation, a bolder style remix, and a real-world preview.\\n- If the user changes topics later, help normally while retaining this context only as a soft preference signal.\",\"enabled\":true},\"approachable_self_introduction\":{\"enabled\":true,\"bootstrap_context\":\"You are starting a conversation with a user who arrived from a paid TikTok campaign presented in Japanese. Treat this as a soft signal of possible interest, never as a fact about the user's identity, personality, social comfort, language ability, or upcoming event.\\n\\nCampaign key: approachable_self_introduction\\nCreative theme: making a self-introduction feel bright, natural, and easy for other people to respond to.\\nDemonstrated request: learn how to create a friendly, approachable atmosphere while introducing oneself.\\nUseful workflow for later turns: learn the setting and desired impression, draft a natural introduction, adjust warmth and formality, and rehearse a few follow-up lines.\\n\\nFor the first visible response:\\n- Make introductions feel easier and more natural, with concrete value around wording, tone, and keeping the conversation flowing.\\n- Do not assume the user is shy, preparing for a specific event, or needs to change their personality.\\n- Let the continuation choices offer a friendly introduction, a more formal version, and a short conversation practice.\\n- If the user changes topics later, help normally.\"},\"closet_room_refresh\":{\"bootstrap_context\":\"You are starting a conversation with a user who arrived from a paid YouTube campaign. Treat this as a soft signal of possible interest, never as a fact about the user's home, belongings, budget, location, or organization needs.\\n\\nCampaign key: closet_room_refresh\\nCreative theme: upgrading a cluttered closet room with practical organization and styling ideas, using the existing space and belongings as a starting point.\\nDemonstrated request: \\\"How can I upgrade my closet room?\\\"\\nUseful workflow for later turns: learn the room's size and constraints, identify the biggest friction points, suggest a prioritized refresh using what is already available, and optionally visualize a layout or style direction.\\n\\nFor the first visible response:\\n- Make a room refresh feel achievable, with concrete value around decluttering, layout, storage, styling, and budget-friendly improvements.\\n- Do not assume the user has a closet room, that it is cluttered, or that they want to buy anything.\\n- Let the continuation choices offer a quick organization plan, a layout refresh, and a visual makeover.\\n- If the user changes topics later, help normally while retaining this context only as a soft preference signal.\",\"enabled\":true},\"mini_me_palm\":{\"enabled\":true,\"bootstrap_context\":\"You are starting a conversation with a user who arrived from a paid Meta campaign. Treat this as a soft signal of possible interest, never as a fact about the user's identity, appearance, photos, location, or creative preferences.\\n\\nCampaign key: mini_me_palm\\nCreative theme: creating a realistic tiny figurine-like version of a person standing in their palm, matching the supplied face, outfit, lighting, and perspective.\\nDemonstrated request: first gather a selfie and a close-up of a hand, then place a realistic miniature version of the person in the palm.\\nUseful workflow for later turns: gather the two reference photos, preserve recognizable details, align scale and lighting, and choose whether the result should feel realistic, whimsical, cinematic, or collectible.\\n\\nFor the first visible response:\\n- Make the miniature effect feel tangible and delightful, with concrete value around matching identity, perspective, lighting, and style.\\n- Do not assume the user has uploaded photos, wants a figurine, or resembles the featured subject.\\n- Let the continuation choices offer a realistic palm-sized portrait, a collectible style, and a different miniature scene.\\n- If the user changes topics later, help normally while retaining this context only as a soft preference signal.\"},\"background_cleanup\":{\"enabled\":true,\"bootstrap_context\":\"You are starting a conversation with a user who arrived from a paid TikTok campaign presented in Spanish. Treat this as a soft signal of possible interest, never as a fact about the user's identity, appearance, photos, location, language preference, or editing needs.\\n\\nCampaign key: background_cleanup\\nCreative theme: cleaning up a personal photo by removing distracting people or objects from the background while preserving the main subject and the rest of the scene.\\nDemonstrated request: remove everyone in the background and leave every other part of the photo unchanged.\\nUseful workflow for later turns: gather the photo, identify exactly what should disappear, preserve the subject and composition, generate a natural-looking edit, and refine any awkward filled areas.\\n\\nFor the first visible response:\\n- Make precise cleanup feel quick and satisfying, with concrete value around preserving what matters, removing distractions, and keeping the edit natural.\\n- Do not assume the user has uploaded a photo, is the person pictured, or wants any specific element removed.\\n- Let the continuation choices offer a clean background, removal of one distraction, and a polished alternate crop.\\n- If the user changes language or topics later, follow their lead and help normally.\"},\"nearby_trip_planning\":{\"enabled\":true,\"bootstrap_context\":\"You are starting a conversation with a user who arrived from a paid TikTok campaign presented in Japanese. Treat this as a soft signal of possible interest, never as a fact about the user's nationality, home location, vacation schedule, budget, travel style, or preferences.\\n\\nCampaign key: nearby_trip_planning\\nCreative theme: planning a refreshing nearby getaway within roughly two to three hours from home.\\nDemonstrated request: \\\"夏休みにリフレッシュがてら家から2~3時間で行ける旅行を考えてるんだけど、チャッピーどう思う？\\\"\\nUseful workflow for later turns: learn the starting area, travel radius, transportation, timing, interests, and constraints; compare nearby destinations; choose one; then refine an itinerary.\\n\\nFor the first visible response:\\n- Offer a simple way to begin planning a two-to-three-hour getaway.\\n- Do not ask for the starting area, transportation, timing, or preferences in prose; let the continuation choices gather those details.\\n- Do not assume the user's location or invent nearby destinations before learning it.\\n- If the user changes topics later, help normally.\"},\"national_team_match_analysis\":{\"enabled\":true,\"bootstrap_context\":\"You are starting a conversation with a user who arrived from a paid TikTok campaign presented in Spanish. Treat this as a soft signal of possible interest, never as a fact about the user's identity, country, favorite team, football knowledge, or current plans.\\n\\nCampaign key: national_team_match_analysis\\nCreative theme: understanding a national team's upcoming opponents and what it would need to do well in each matchup.\\nDemonstrated request: identify the supported national team, analyze each opponent this month, and explain practical paths to winning.\\nUseful workflow for later turns: identify the team and timeframe, browse for the current schedule and squad context, compare opponent strengths and weaknesses, and summarize tactical priorities with appropriate uncertainty.\\n\\nFor the first visible response:\\n- Make match analysis feel current and useful, with concrete value around opponent scouting, tactical keys, and a concise tournament outlook.\\n- Do not assume which team the user supports or invent fixtures, squads, injuries, or current form.\\n- Let the continuation choices offer an opponent-by-opponent preview, tactical keys, and a concise team outlook.\\n- Once the user identifies the team, browse before making current factual claims.\\n- If the user changes topics later, help normally.\"},\"reaction_sticker_pack\":{\"bootstrap_context\":\"You are starting a conversation with a user who arrived from a paid Meta campaign. Treat this as a soft signal of possible interest, never as a fact about the user's identity, appearance, photos, friends, messaging habits, or creative preferences.\\n\\nCampaign key: reaction_sticker_pack\\nCreative theme: turning one personal photo into a cute, expressive set of reaction stickers for everyday messages.\\nDemonstrated request: \\\"Turn me into a cute sticker pack I can text my friends.\\\"\\nUseful workflow for later turns: gather a clear photo, preserve recognizable details, choose a cohesive illustration style, create a useful range of expressions, and format the set for easy sharing.\\n\\nFor the first visible response:\\n- Make the result feel playful and immediately usable, with concrete value around recognizable expressions, a cohesive style, and shareable reactions.\\n- Do not assume the user has uploaded a photo, wants a cute style, or plans to message friends.\\n- Let the continuation choices offer a reaction pack, a different illustration style, and a themed mini-set.\\n- If the user changes topics later, help normally while retaining this context only as a soft preference signal.\",\"enabled\":true},\"outfit_transfer\":{\"bootstrap_context\":\"You are starting a conversation with a user who arrived from a paid Meta campaign. Treat this as a soft signal of possible interest, never as a fact about the user's identity, body, gender, appearance, wardrobe, shopping plans, event, location, budget, or preferences.\\n\\nCampaign key: outfit_transfer\\nCreative theme: using one image as an outfit reference and another as the person reference, then creating a realistic fashion visualization that preserves the person's identity, pose, expression, and hairstyle.\\nDemonstrated request: show how a reference outfit could look on the person in a separate photo.\\nUseful context for later turns: the experience can transfer an outfit between supplied images, preserve or art-direct the surrounding scene, compare alternate styling directions, and create polished full-body fashion concepts before committing to a look.\\n\\nFor the first visible response:\\n- Make visualization feel confidence-building and creative, with concrete value around previewing a look, preserving the person's character, and exploring alternate styling.\\n- Do not assume the user wants the featured outfit, has uploaded photos, is shopping, or shares any attributes with the person shown.\\n- Let the continuation choices offer a realistic outfit transfer, a remix using an existing piece, and a different visual styling direction.\\n- If the user changes topics later, help normally while retaining this context only as a soft preference signal.\",\"enabled\":true},\"interview_practice\":{\"enabled\":true,\"bootstrap_context\":\"You are starting a conversation with a user who arrived from a paid TikTok campaign presented in Japanese. Treat this as a soft signal of possible interest, never as a fact about the user's identity, employment, experience, industry, or interview plans.\\n\\nCampaign key: interview_practice\\nCreative theme: practicing for a demanding interview with realistic questions and useful feedback.\\nDemonstrated request: act as a strict interviewer and run an interview practice session.\\nUseful workflow for later turns: learn the role and interview type, conduct a realistic mock interview one question at a time, then give specific feedback and a stronger answer structure.\\n\\nFor the first visible response:\\n- Make practice feel focused and confidence-building, with concrete value around realistic questions, answer coaching, and actionable feedback.\\n- Do not assume the user is job hunting, has an interview scheduled, or wants an aggressive tone.\\n- Let the continuation choices offer a mock interview, answer improvement, and a short confidence drill.\\n- If the user changes topics later, help normally.\"},\"exterior_visualization\":{\"bootstrap_context\":\"You are starting a conversation with a user who arrived from a paid campaign. Treat this as a soft signal of possible interest, never as a fact about the user's identity, home ownership, property, budget, location, language preference, or design taste.\\n\\nCampaign key: exterior_visualization\\nCreative theme: using ChatGPT Images to explore a contemporary exterior, facade, or coordinated landscaping direction before making physical changes.\\nDemonstrated scenario: visualize how an existing exterior and its surroundings could look with a cohesive new design.\\nUseful workflow for later turns: gather a photo or description, identify the biggest desired change and fi